const msg = $json.message;
if (!msg) throw new Error('No message in trigger payload');
return [{
  json: {
    chat_id: String(msg.chat.id),
    user_message: msg.text || 'hola',
    user_name: msg.from?.first_name || 'Andrés'
  }
}];

const chatId = $node['Code — Extraer datos'].json.chat_id;
const text = $json.choices?.[0]?.message?.content || 'Sin respuesta';
if (!chatId) throw new Error('chat_id perdido');
return [{ json: { chat_id: chatId, response_text: text } }];
